import{_ as s,o as n,c as e,a1 as p}from"./chunks/framework.BKJzsOC1.js";const u=JSON.parse('{"title":"游戏运行时系统概览：网络、动画与物理","description":"","frontmatter":{},"headers":[],"relativePath":"tech/cpp/game-runtime-systems-overview.md","filePath":"tech/cpp/game-runtime-systems-overview.md"}'),i={name:"tech/cpp/game-runtime-systems-overview.md"};function t(l,a,o,c,h,r){return n(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="游戏运行时系统概览-网络、动画与物理" tabindex="-1">游戏运行时系统概览：网络、动画与物理 <a class="header-anchor" href="#游戏运行时系统概览-网络、动画与物理" aria-label="Permalink to &quot;游戏运行时系统概览：网络、动画与物理&quot;">​</a></h1><p>游戏运行时通常把世界状态、网络同步、动画表现和物理计算拆成不同系统，再通过明确的数据边界连接起来。本篇只保留整体流程和关键概念。</p><h2 id="一、网络同步" tabindex="-1">一、网络同步 <a class="header-anchor" href="#一、网络同步" aria-label="Permalink to &quot;一、网络同步&quot;">​</a></h2><p>实时网络应用需要在延迟、丢包和不同设备性能下，尽量让各端看到一致的世界状态。常见思路是服务器维护权威状态，客户端负责输入、预测和表现。</p><h3 id="状态同步与帧同步" tabindex="-1">状态同步与帧同步 <a class="header-anchor" href="#状态同步与帧同步" aria-label="Permalink to &quot;状态同步与帧同步&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>状态同步：服务器发送“结果是什么”</span></span>
<span class="line"><span>帧同步：服务器发送“玩家做了什么”，各端根据输入模拟结果</span></span></code></pre></div><p>状态同步直接传输对象位置、世界状态等结果，客户端主要负责显示和插值；帧同步主要传输输入，要求各端模拟逻辑更加一致。</p><p>实际系统可以混合使用，关键是明确：</p><ul><li>哪些状态由服务器最终决定；</li><li>哪些输入由客户端提交；</li><li>哪些结果必须可靠到达；</li><li>断线、重连和校正如何处理。</li></ul><h3 id="tcp-与-udp" tabindex="-1">TCP 与 UDP <a class="header-anchor" href="#tcp-与-udp" aria-label="Permalink to &quot;TCP 与 UDP&quot;">​</a></h3><p>TCP 提供可靠、有序的字节流，适合登录、账号、商城、聊天和资源下载等必须完整到达的数据。丢包时，TCP 可能等待旧数据，造成队头阻塞。</p><p>UDP 不保证到达和顺序，但应用可以自己决定可靠性策略。高频位置通常采用“最新状态优先”，旧包丢失后不必等待；关键事件和状态切换则需要确认或重传。</p><p>因此重点不是“TCP 或 UDP 谁更快”，而是判断：</p><blockquote><p>这条消息丢失后，旧数据还有价值吗？是否必须等待？最终结果由谁确认？</p></blockquote><h3 id="预测、校正与插值" tabindex="-1">预测、校正与插值 <a class="header-anchor" href="#预测、校正与插值" aria-label="Permalink to &quot;预测、校正与插值&quot;">​</a></h3><p>本地玩家的输入已经被客户端知道，可以先立即预测：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>本地输入</span></span>
<span class="line"><span>    ├── 立即更新本地表现</span></span>
<span class="line"><span>    └── 发送给服务器</span></span></code></pre></div><p>服务器返回权威状态后，客户端比较差异并进行校正。远端玩家的下一步输入未知，通常不直接预测，而是在两个已知服务器状态之间插值，以减少抖动。</p><h3 id="tick-与固定时间步" tabindex="-1">Tick 与固定时间步 <a class="header-anchor" href="#tick-与固定时间步" aria-label="Permalink to &quot;Tick 与固定时间步&quot;">​</a></h3><p>渲染帧率可能是 30、60 或 120 FPS，但游戏逻辑和物理通常使用固定 Tick：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tick 100 → Tick 101 → Tick 102 → Tick 103</span></span></code></pre></div><p>输入、状态快照和校正都可以带 Tick 编号，用来处理乱序、重复和重放。固定时间步让模拟节奏稳定，同时允许渲染以另一种频率运行。</p><h2 id="二、骨骼动画" tabindex="-1">二、骨骼动画 <a class="header-anchor" href="#二、骨骼动画" aria-label="Permalink to &quot;二、骨骼动画&quot;">​</a></h2><p>骨骼动画由骨骼层级和 Mesh 组成。骨骼保存层级关系与姿态，Mesh 顶点根据一个或多个骨骼的影响权重进行蒙皮。</p><h3 id="基本动画管线" tabindex="-1">基本动画管线 <a class="header-anchor" href="#基本动画管线" aria-label="Permalink to &quot;基本动画管线&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>游戏状态</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>选择动画状态</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>采样 Animation Clip</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>混合多个姿态</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>IK 等局部修正</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>生成骨骼矩阵</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>蒙皮并绘制 Mesh</span></span></code></pre></div><p>例如，角色速度增加时从 Idle 切换到 Run，用户触发技能动作时从 Run 过渡到 Action。</p><h3 id="状态机与动画混合" tabindex="-1">状态机与动画混合 <a class="header-anchor" href="#状态机与动画混合" aria-label="Permalink to &quot;状态机与动画混合&quot;">​</a></h3><p>状态机回答“当前应该播放什么动画、何时切换”。混合则避免状态切换时突然跳变：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Run Pose × (1 - weight)</span></span>
<span class="line"><span>+ Shoot Pose × weight</span></span></code></pre></div><p><code>weight</code> 在一段时间内从 0 变化到 1，角色就能从跑步自然过渡到目标动作。</p><h3 id="ik-与移动控制" tabindex="-1">IK 与移动控制 <a class="header-anchor" href="#ik-与移动控制" aria-label="Permalink to &quot;IK 与移动控制&quot;">​</a></h3><p>普通动画提供基础姿态，IK 根据当前环境修正局部骨骼，例如让脚贴合地面、让手对准物体、让手脚接触目标。</p><p>角色移动可以由代码控制，也可以由动画的 Root Motion 控制。代码控制更容易与网络和物理结合；Root Motion 更容易保持特定动作与位移的一致。实际项目可能混合使用。</p><p>游戏逻辑负责动作是否成功、对象速度和权威位置；动画系统主要负责抬腿、转身、过渡等表现。</p><h2 id="三、物理管线" tabindex="-1">三、物理管线 <a class="header-anchor" href="#三、物理管线" aria-label="Permalink to &quot;三、物理管线&quot;">​</a></h2><p>物理系统通常按照下面的顺序工作：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>积分更新</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Broad Phase 粗检测</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Narrow Phase 精检测</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Solver 求解碰撞和约束</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>输出位置、速度和碰撞事件</span></span></code></pre></div><h3 id="粗检测与精检测" tabindex="-1">粗检测与精检测 <a class="header-anchor" href="#粗检测与精检测" aria-label="Permalink to &quot;粗检测与精检测&quot;">​</a></h3><p>粗检测使用 AABB、空间网格或层次包围盒，快速找出可能相交的物体对。精检测再计算真实的碰撞点、法线和穿透深度。</p><p>渲染 Mesh 可以很复杂，但 Collider 通常使用球体、盒体、胶囊体等简单形状，以降低计算成本。</p><h3 id="检测与响应" tabindex="-1">检测与响应 <a class="header-anchor" href="#检测与响应" aria-label="Permalink to &quot;检测与响应&quot;">​</a></h3><p>碰撞检测回答：</p><blockquote><p>两个物体是否发生接触？接触信息是什么？</p></blockquote><p>碰撞响应回答：</p><blockquote><p>接触后如何修改位置和速度？是否反弹、摩擦或被推出？</p></blockquote><p>Trigger 只产生进入、离开等事件，不产生实体阻挡；普通 Collision 会参与物理响应。</p><h3 id="固定时间步与高速物体" tabindex="-1">固定时间步与高速物体 <a class="header-anchor" href="#固定时间步与高速物体" aria-label="Permalink to &quot;固定时间步与高速物体&quot;">​</a></h3><p>物理通常使用固定时间步，以避免不同帧率导致模拟结果明显变化。如果高速物体移动得很快，可能从障碍物前面直接跳到障碍物后面，离散检测就会漏掉碰撞。这种穿透问题可以用更小的时间步、连续碰撞检测或扫掠检测处理。</p><h2 id="四、系统之间如何连接" tabindex="-1">四、系统之间如何连接 <a class="header-anchor" href="#四、系统之间如何连接" aria-label="Permalink to &quot;四、系统之间如何连接&quot;">​</a></h2><p>一个简化的运行时流程如下：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>网络输入</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>游戏逻辑更新世界状态</span></span>
<span class="line"><span>    ├── 物理计算位置和碰撞</span></span>
<span class="line"><span>    ├── 动画系统生成角色姿态</span></span>
<span class="line"><span>    └── 生成 Render Snapshot</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>        渲染线程消费只读快照</span></span></code></pre></div><p>游戏线程不必让渲染线程直接读取正在修改的世界对象，而是生成稳定的渲染快照。这样可以减少跨线程锁，也避免渲染线程看到更新一半的数据。</p><h2 id="本篇结论" tabindex="-1">本篇结论 <a class="header-anchor" href="#本篇结论" aria-label="Permalink to &quot;本篇结论&quot;">​</a></h2><ol><li>网络同步的核心是服务器权威、客户端预测、状态校正和远端插值。</li><li>TCP 适合可靠业务数据，UDP 适合由应用自行决定可靠性的实时数据。</li><li>Tick 是游戏逻辑的时间单位，固定时间步让模拟更稳定。</li><li>动画管线通常是状态选择、采样、混合、IK、骨骼矩阵和蒙皮。</li><li>物理管线通常是积分、粗检测、精检测、求解和输出。</li><li>游戏逻辑负责权威状态，动画和渲染主要负责表现，系统之间通过快照或明确的数据边界连接。</li></ol><p><a href="./atomics-memory-order-task-system.html">← 上一章：Atomic、内存序与任务系统</a> · <a href="./../cpp-engine-foundations.html">返回学习地图</a></p>`,56)])])}const b=s(i,[["render",t]]);export{u as __pageData,b as default};
